export function getProductsByCategory(categorySlug: string): Product[] {
  return products.filter((p) => p.categorySlug === categorySlug)
}

export function getProductBySlug(slug: string): Product | undefined {
  return products.find((p) => p.slug === slug)
}

export function getFeaturedProducts(): Product[] {
  return products.filter((p) => p.featured)
}

export function getNewArrivals(): Product[] {
  return products.filter((p) => p.featured).slice(0, 8)
}

export const products: Product[] = raw.map((item) => ({
  ...item,
  slug: slug(item.name),
  shortDescription: desc(item.name),
  description: desc(item.name),
  wholesalePrice: item.price,
  compareAtPrice: Math.round(item.price * 1.3 * 100) / 100,
  imageUrl: item.imageUrl || '/images/products/placeholder.avif',
  stock: 999,
  inStock: true,
  rating: 4.5,
  reviewCount: 0,
}));
